/**
 * Integration test: Event Pipeline (DB event → hookProcessor → metricsStore)
 *
 * This test exercises the full frontend event pipeline using production-shaped
 * event payloads (as returned by Tauri IPC `get_session_events`).
 *
 * The bug this catches: hookProcessor received the full DB event wrapper
 * { session_id, event_type, payload: { usage: {...} }, ... } but passed it
 * as-is to the aggregator. The token extractor looked for `payload.usage`
 * at the wrong nesting level and always returned "absent".
 *
 * This test wires up the real plugin onLoad, feeds production-shaped events
 * through the registered hook processor, and asserts the metrics store
 * reflects extracted tokens and computed costs.
 *
 * NOTE: usageMetricsStore is a module-level singleton that accumulates state
 * across tests. Tests use delta assertions (before/after) instead of absolute
 * values.
 */

import { describe, it, expect, beforeAll } from "vitest";
import { usageMetricsStore } from "../../../../src/plugins/norbert-usage/index";
import { norbertUsagePlugin } from "../../../../src/plugins/norbert-usage/index";
import { resetHookBridge, deliverHookEvent } from "../../../../src/plugins/hookBridge";
import { createPluginRegistry } from "../../../../src/plugins/pluginRegistry";
import { createNorbertAPI } from "../../../../src/plugins/apiFactory";
import { loadPlugins } from "../../../../src/plugins/lifecycleManager";
import { norbertSessionPlugin } from "../../../../src/plugins/norbert-session/index";

// ---------------------------------------------------------------------------
// Production event shapes — exactly what get_session_events returns via IPC
// ---------------------------------------------------------------------------

/** A PostToolUse event WITH token usage (tool_call_end in canonical form). */
const makeWrappedToolCallEndWithUsage = (sessionId: string) => ({
  session_id: sessionId,
  event_type: "tool_call_end",
  payload: {
    session_id: sessionId,
    tool: "Read",
    input: { file_path: "/tmp/test.ts" },
    usage: {
      input_tokens: 1200,
      output_tokens: 400,
      cache_read_input_tokens: 500,
      cache_creation_input_tokens: 0,
      model: "claude-sonnet-4-20250514",
    },
  },
  received_at: "2026-03-13T22:00:00Z",
  provider: "claude_code",
});

/** A SessionStart event (no token data expected). */
const makeWrappedSessionStart = (sessionId: string) => ({
  session_id: sessionId,
  event_type: "session_start",
  payload: {
    session_id: sessionId,
  },
  received_at: "2026-03-13T21:59:00Z",
  provider: "claude_code",
});

/** A PreToolUse event (tool_call_start, no token data). */
const makeWrappedToolCallStart = (sessionId: string) => ({
  session_id: sessionId,
  event_type: "tool_call_start",
  payload: {
    session_id: sessionId,
    tool: "Read",
    input: { file_path: "/tmp/test.ts" },
  },
  received_at: "2026-03-13T22:00:00Z",
  provider: "claude_code",
});

/** A UserPromptSubmit event WITH token usage (prompt_submit). */
const makeWrappedPromptSubmit = (sessionId: string) => ({
  session_id: sessionId,
  event_type: "prompt_submit",
  payload: {
    session_id: sessionId,
    usage: {
      input_tokens: 3000,
      output_tokens: 1500,
      cache_read_input_tokens: 0,
      cache_creation_input_tokens: 0,
      model: "claude-opus-4-20250514",
    },
  },
  received_at: "2026-03-13T22:01:00Z",
  provider: "claude_code",
});

// ---------------------------------------------------------------------------
// Integration tests
// ---------------------------------------------------------------------------

describe("Event pipeline integration: DB event → hookBridge → metricsStore", () => {
  beforeAll(() => {
    // Initialize plugin system once (same as App.tsx does on mount)
    resetHookBridge();
    loadPlugins(
      [norbertSessionPlugin, norbertUsagePlugin],
      createPluginRegistry(),
      createNorbertAPI,
    );
  });

  it("tool_call_end with usage data produces non-zero tokens and cost in the store", () => {
    const before = usageMetricsStore.getMetrics();
    const event = makeWrappedToolCallEndWithUsage("sess-integration-1");

    deliverHookEvent("session-event", event);

    const after = usageMetricsStore.getMetrics();
    const deltaTokens = after.totalTokens - before.totalTokens;
    expect(deltaTokens).toBe(1600); // 1200 input + 400 output
    expect(after.inputTokens - before.inputTokens).toBe(1200);
    expect(after.outputTokens - before.outputTokens).toBe(400);
    expect(after.sessionCost).toBeGreaterThan(before.sessionCost);
    expect(after.hookEventCount).toBeGreaterThan(before.hookEventCount);
  });

  it("session_start event increments activeAgentCount without adding tokens", () => {
    const before = usageMetricsStore.getMetrics();
    const event = makeWrappedSessionStart("sess-integration-2");

    deliverHookEvent("session-event", event);

    const after = usageMetricsStore.getMetrics();
    expect(after.activeAgentCount).toBe(before.activeAgentCount + 1);
    expect(after.totalTokens).toBe(before.totalTokens); // no change
    expect(after.sessionCost).toBe(before.sessionCost); // no change
    expect(after.hookEventCount).toBe(before.hookEventCount + 1);
  });

  it("tool_call_start increments toolCallCount without adding tokens", () => {
    const before = usageMetricsStore.getMetrics();
    const event = makeWrappedToolCallStart("sess-integration-3");

    deliverHookEvent("session-event", event);

    const after = usageMetricsStore.getMetrics();
    expect(after.toolCallCount).toBe(before.toolCallCount + 1);
    expect(after.totalTokens).toBe(before.totalTokens); // no change
  });

  it("prompt_submit with usage data adds tokens and cost", () => {
    const before = usageMetricsStore.getMetrics();
    const event = makeWrappedPromptSubmit("sess-integration-4");

    deliverHookEvent("session-event", event);

    const after = usageMetricsStore.getMetrics();
    expect(after.totalTokens - before.totalTokens).toBe(4500); // 3000 + 1500
    expect(after.inputTokens - before.inputTokens).toBe(3000);
    expect(after.outputTokens - before.outputTokens).toBe(1500);
    expect(after.sessionCost).toBeGreaterThan(before.sessionCost);
  });

  it("time series buffer receives samples when token events flow", () => {
    const timeSeries = usageMetricsStore.getTimeSeries();
    // Previous token-bearing events should have pushed samples
    expect(timeSeries.samples.length).toBeGreaterThanOrEqual(1);
    expect(timeSeries.samples[0].tokenRate).toBeGreaterThan(0);
  });
});

tests/acceptance/norbert-performance-mon.source:
/**
 * Acceptance tests: Cross-Session Aggregate Metrics (US-PM-002, US-PM-006)
 *
 * Validates that aggregate metrics are correctly computed from multiple
 * active sessions: total tokens/s, total cost/min, active agent counts,
 * and per-session breakdown sorted by rate.
 *
 * Driving ports: pure domain functions (crossSessionAggregator,
 * performanceMonitor chart data composition)
 * These tests exercise the aggregation pipeline, not React views.
 *
 * Traces to: US-PM-002 acceptance criteria, US-PM-006 acceptance criteria
 */

import { describe, it, expect } from "vitest";
import {
  createInitialMetrics,
  type SessionMetrics,
} from "../../../src/plugins/norbert-usage/domain/metricsAggregator";
import {
  aggregateAcrossSessions,
  type AggregateMetrics,
} from "../../../src/plugins/norbert-usage/domain/crossSessionAggregator";

import {
  computeCostRatePerMinute,
  estimateSessionCostRate,
} from "../../../src/plugins/norbert-usage/domain/performanceMonitor";

// ---------------------------------------------------------------------------
// Helper: create session metrics with specific values
// ---------------------------------------------------------------------------

const createSessionSnapshot = (
  overrides: Partial<SessionMetrics> & { sessionId: string },
): SessionMetrics => ({
  ...createInitialMetrics(overrides.sessionId),
  ...overrides,
});

// ---------------------------------------------------------------------------
// WALKING SKELETON: User sees total resource consumption across sessions
// Traces to: US-PM-002, JS-PM-1
// ---------------------------------------------------------------------------

describe("User views aggregate resource consumption across all active sessions", () => {
  it("total token rate equals sum of per-session rates", () => {
    // Given Ravi has 3 active sessions with known token rates
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "refactor-auth", burnRate: 312 }),
      createSessionSnapshot({ sessionId: "migrate-db", burnRate: 185 }),
      createSessionSnapshot({ sessionId: "test-coverage", burnRate: 30 }),
    ];

    // When aggregate metrics are computed across all sessions
    const aggregate = aggregateAcrossSessions(sessions);

    // Then the total tokens/s shows 527 tok/s
    expect(aggregate.totalTokenRate).toBe(527);
    // And the session count is 3
    expect(aggregate.sessionCount).toBe(3);
    // And per-session breakdown lists all 3 sessions
    expect(aggregate.sessions).toHaveLength(3);
  });
});

// ---------------------------------------------------------------------------
// WALKING SKELETON: User sees cost velocity as a leading indicator
// Traces to: US-PM-006, JS-PM-5
// ---------------------------------------------------------------------------

describe("User sees rolling cost rate across all active sessions", () => {
  it("total cost rate reflects sum of per-session cost rates", () => {
    // Given Ravi has sessions with varying cost rates:
    // Opus 4 "refactor-auth" at $0.003/s, Opus 4 "migrate-db" at $0.002/s,
    // Sonnet 4 "test-coverage" at $0.0003/s
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "refactor-auth", burnRate: 312, sessionCost: 5.40 }),
      createSessionSnapshot({ sessionId: "migrate-db", burnRate: 185, sessionCost: 3.20 }),
      createSessionSnapshot({ sessionId: "test-coverage", burnRate: 30, sessionCost: 0.12 }),
    ];

    // When aggregate metrics are computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then the total cost rate equals the sum of per-session cost rates
    const expectedTotalCostRate = sessions.reduce(
      (sum, s) => sum + estimateSessionCostRate(s),
      0,
    );
    expect(aggregate.totalCostRate).toBeCloseTo(expectedTotalCostRate);
    // And the cost/min display shows the rate in dollars per minute
    const costPerMin = computeCostRatePerMinute(aggregate.totalCostRate);
    const expectedCostPerMin = computeCostRatePerMinute(expectedTotalCostRate);
    expect(costPerMin).toBeCloseTo(expectedCostPerMin);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Aggregate Computation
// Traces to: US-PM-002 AC
// ---------------------------------------------------------------------------

describe("Aggregate token rate is the sum of per-session burn rates", () => {
  it("sums token rates across 3 mixed-model sessions", () => {
    // Given 3 sessions at 312, 185, and 30 tok/s
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "refactor-auth", burnRate: 312 }),
      createSessionSnapshot({ sessionId: "migrate-db", burnRate: 185 }),
      createSessionSnapshot({ sessionId: "test-coverage", burnRate: 30 }),
    ];

    // When aggregate metrics are computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then the total is 527 tok/s
    expect(aggregate.totalTokenRate).toBe(527);
  });
});

describe("Aggregate active agents is the sum of per-session agent counts", () => {
  it("sums agent counts across sessions", () => {
    // Given 3 sessions with 1, 2, and 1 active agents respectively
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "refactor-auth", activeAgentCount: 1 }),
      createSessionSnapshot({ sessionId: "migrate-db", activeAgentCount: 2 }),
      createSessionSnapshot({ sessionId: "test-coverage", activeAgentCount: 1 }),
    ];

    // When aggregate metrics are computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then total active agents is 4
    expect(aggregate.totalActiveAgents).toBe(4);
  });
});

describe("Per-session breakdown is sorted by token rate descending", () => {
  it("highest rate session appears first in breakdown", () => {
    // Given 3 sessions with rates 30, 312, and 185 tok/s (unsorted input)
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "test-coverage", burnRate: 30 }),
      createSessionSnapshot({ sessionId: "refactor-auth", burnRate: 312 }),
      createSessionSnapshot({ sessionId: "migrate-db", burnRate: 185 }),
    ];

    // When aggregate metrics are computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then sessions are listed in order: 312, 185, 30 tok/s
    expect(aggregate.sessions[0].tokenRate).toBe(312);
    expect(aggregate.sessions[1].tokenRate).toBe(185);
    expect(aggregate.sessions[2].tokenRate).toBe(30);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Single Session Edge Case
// Traces to: US-PM-001 scenario 2
// ---------------------------------------------------------------------------

describe("Single session aggregate equals that session's metrics", () => {
  it("aggregate matches the sole session when only one is active", () => {
    // Given Elena has only 1 active session "user-auth" at 280 tok/s
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "user-auth", burnRate: 280, activeAgentCount: 1 }),
    ];

    // When aggregate metrics are computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then the total tokens/s matches the single session rate
    expect(aggregate.totalTokenRate).toBe(280);
    // And session count is 1
    expect(aggregate.sessionCount).toBe(1);
    // And breakdown shows one row
    expect(aggregate.sessions).toHaveLength(1);
  });
});

// ---------------------------------------------------------------------------
// ERROR SCENARIOS: Empty State
// Traces to: US-PM-001 scenario 3, US-PM-001 AC "Empty state with guidance"
// ---------------------------------------------------------------------------

describe("Empty aggregate when no sessions are active", () => {
  it("all aggregate values are zero with no sessions", () => {
    // Given Marcus has no active Claude Code sessions
    const sessions: ReadonlyArray<SessionMetrics> = [];

    // When aggregate metrics are computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then all aggregate values are zero
    expect(aggregate.totalTokenRate).toBe(0);
    expect(aggregate.totalCostRate).toBe(0);
    expect(aggregate.totalActiveAgents).toBe(0);
    expect(aggregate.sessionCount).toBe(0);
    // And the breakdown is empty
    expect(aggregate.sessions).toHaveLength(0);
  });
});

// ---------------------------------------------------------------------------
// ERROR SCENARIOS: Session Lifecycle Changes
// Traces to: US-PM-002 AC "New sessions appear", "Ended sessions removed"
// ---------------------------------------------------------------------------

describe("Aggregate updates when a new session is added", () => {
  it("total increases when a session is added to the active set", () => {
    // Given Elena has 2 sessions totaling 400 tok/s
    const existingSessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "session-a", burnRate: 250 }),
      createSessionSnapshot({ sessionId: "session-b", burnRate: 150 }),
    ];

    // When a new session "deploy-staging" starts at 80 tok/s
    const updatedSessions: ReadonlyArray<SessionMetrics> = [
      ...existingSessions,
      createSessionSnapshot({ sessionId: "deploy-staging", burnRate: 80 }),
    ];

    // Then the aggregate reflects 3 sessions at 480 tok/s
    const aggregate = aggregateAcrossSessions(updatedSessions);
    expect(aggregate.totalTokenRate).toBe(480);
    expect(aggregate.sessionCount).toBe(3);
  });
});

describe("Aggregate updates when a session ends", () => {
  it("total decreases when a session is removed from the active set", () => {
    // Given Marcus has 3 sessions with total 500 tok/s
    // And session "quick-fix" was contributing 100 tok/s
    const allSessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "session-a", burnRate: 250 }),
      createSessionSnapshot({ sessionId: "quick-fix", burnRate: 100 }),
      createSessionSnapshot({ sessionId: "session-c", burnRate: 150 }),
    ];

    // When session "quick-fix" ends (removed from active set)
    const remainingSessions = allSessions.filter(s => s.sessionId !== "quick-fix");

    // Then the total drops to 400 tok/s
    const aggregate = aggregateAcrossSessions(remainingSessions);
    expect(aggregate.totalTokenRate).toBe(400);
    expect(aggregate.sessionCount).toBe(2);
  });
});

// ---------------------------------------------------------------------------
// ERROR SCENARIOS: Cost Rate Edge Cases
// Traces to: US-PM-006 AC "Zero cost correctly displayed during idle"
// ---------------------------------------------------------------------------

describe("Zero cost rate when all sessions are idle", () => {
  it("cost rate is zero when no tokens are being consumed", () => {
    // Given Marcus has 2 sessions running but both agents are idle
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "session-a", burnRate: 0 }),
      createSessionSnapshot({ sessionId: "session-b", burnRate: 0 }),
    ];

    // When aggregate metrics are computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then the total cost rate is zero
    expect(aggregate.totalCostRate).toBe(0);
    // And the total token rate is zero
    expect(aggregate.totalTokenRate).toBe(0);
    // And cost per minute is also zero
    const costPerMin = computeCostRatePerMinute(aggregate.totalCostRate);
    expect(costPerMin).toBe(0);
  });
});

// ---------------------------------------------------------------------------
// PROPERTY-SHAPED SCENARIOS
// Traces to: Shared Artifacts Registry -- "Aggregate always equals sum of parts"
// ---------------------------------------------------------------------------

describe("@property: aggregate total always equals sum of per-session values", () => {
  it("sum invariant holds for any combination of session metrics", () => {
    // Given any valid set of active sessions with varying metrics
    const sessions: ReadonlyArray<SessionMetrics> = [
      createSessionSnapshot({ sessionId: "s1", burnRate: 100, activeAgentCount: 1 }),
      createSessionSnapshot({ sessionId: "s2", burnRate: 0, activeAgentCount: 2 }),
      createSessionSnapshot({ sessionId: "s3", burnRate: 999, activeAgentCount: 1 }),
      createSessionSnapshot({ sessionId: "s4", burnRate: 1, activeAgentCount: 0 }),
    ];

    // When aggregate metrics are computed
    const aggregate = aggregateAcrossSessions(sessions);

    // Then aggregate totals equal the sum of per-session values
    const expectedTokenRate = sessions.reduce((sum, s) => sum + s.burnRate, 0);
    const expectedAgents = sessions.reduce((sum, s) => sum + s.activeAgentCount, 0);
    expect(aggregate.totalTokenRate).toBe(expectedTokenRate);
    expect(aggregate.totalActiveAgents).toBe(expectedAgents);
  });
});

tests/acceptance/norbert-usage/usage-das.source:
/**
 * Acceptance tests: Default Usage Dashboard View (US-006)
 *
 * Validates that the Usage Dashboard computes correct metric card data
 * from SessionMetrics, including the 7-day burn chart and onboarding state.
 *
 * Driving ports: pure domain functions (metrics -> dashboard card data,
 * daily cost aggregation)
 *
 * Traces to: US-006 acceptance criteria
 */

import { describe, it, expect } from "vitest";
import {
  createInitialMetrics,
  type SessionMetrics,
} from "../../../src/plugins/norbert-usage/domain/metricsAggregator";
import {
  computeDashboardData,
  type DashboardData,
  type DailyCostEntry,
} from "../../../src/plugins/norbert-usage/domain/dashboard";

// ---------------------------------------------------------------------------
// Helper: create metrics snapshot with specific values
// ---------------------------------------------------------------------------

const createMetricsSnapshot = (overrides: Partial<SessionMetrics> = {}): SessionMetrics => ({
  ...createInitialMetrics("test-session"),
  ...overrides,
});

// ---------------------------------------------------------------------------
// WALKING SKELETON
// ---------------------------------------------------------------------------

// @walking_skeleton
describe("User opens Usage Dashboard and sees session health at a glance", () => {
  it("dashboard shows all 6 metric cards with current session values", () => {
    // Given an active session with known metrics
    const metrics = createMetricsSnapshot({
      sessionId: "user-auth-rewrite",
      sessionCost: 2.3,
      totalTokens: 112400,
      inputTokens: 62000,
      outputTokens: 50400,
      activeAgentCount: 1,
      toolCallCount: 89,
      contextWindowPct: 56,
      hookEventCount: 200,
    });

    // When the dashboard data is computed
    const dashboard = computeDashboardData(metrics);

    // Then the running cost card shows "$2.30"
    expect(dashboard.runningCost.value).toBe("$2.30");

    // And the token count card shows "112,400" with breakdown
    expect(dashboard.tokenCount.value).toBe("112,400");
    expect(dashboard.tokenCount.subtitle).toContain("62k in");
    expect(dashboard.tokenCount.subtitle).toContain("50k out");

    // And the active agents card shows "1"
    expect(dashboard.activeAgents.value).toBe("1");

    // And the tool calls card shows "89"
    expect(dashboard.toolCalls.value).toBe("89");

    // And the context window card shows "56%"
    expect(dashboard.contextWindow.value).toBe("56%");

    // And the hook health card shows "OK" (events are flowing)
    expect(dashboard.hookHealth.value).toBe("OK");
    expect(dashboard.hookHealth.urgency).toBe("normal");
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: 7-Day Burn Chart
// ---------------------------------------------------------------------------

describe("Dashboard shows 7-day burn chart from daily costs", () => {
  it("computes one bar per day with proportional cost values", () => {
    // Given daily cost entries over the past 7 days
    const dailyCosts: DailyCostEntry[] = [
      { date: "2025-03-07", totalCost: 4.2, sessionCount: 2 },
      { date: "2025-03-08", totalCost: 6.1, sessionCount: 3 },
      { date: "2025-03-09", totalCost: 3.8, sessionCount: 1 },
      { date: "2025-03-10", totalCost: 8.5, sessionCount: 4 },
      { date: "2025-03-11", totalCost: 5.2, sessionCount: 2 },
      { date: "2025-03-12", totalCost: 2.9, sessionCount: 1 },
      { date: "2025-03-13", totalCost: 3.1, sessionCount: 2 },
    ];

    // When daily costs are computed for the burn chart
    // Then there are 7 entries
    expect(dailyCosts).toHaveLength(7);
    // And the highest cost day is $8.50
    const maxCost = Math.max(...dailyCosts.map((d) => d.totalCost));
    expect(maxCost).toBeCloseTo(8.5);
    // And the lowest cost day is $2.90
    const minCost = Math.min(...dailyCosts.map((d) => d.totalCost));
    expect(minCost).toBeCloseTo(2.9);
  });
});

describe("Dashboard updates metric cards when new events arrive", () => {
  it("recomputed dashboard data reflects updated session metrics", () => {
    // Given the dashboard is showing cost "$2.30"
    const metrics1 = createMetricsSnapshot({ sessionCost: 2.3 });
    const dashboard1 = computeDashboardData(metrics1);
    expect(dashboard1.runningCost.value).toBe("$2.30");

    // When a new event adds $0.15 to the session cost
    const metrics2 = createMetricsSnapshot({ sessionCost: 2.45 });
    const dashboard2 = computeDashboardData(metrics2);

    // Then the running cost card updates to "$2.45"
    expect(dashboard2.runningCost.value).toBe("$2.45");
  });
});

// ---------------------------------------------------------------------------
// ERROR / BOUNDARY SCENARIOS
// ---------------------------------------------------------------------------

describe("Dashboard shows onboarding state for new user", () => {
  it("metric cards show placeholder values when no session data exists", () => {
    // Given a new user with no session history
    const metrics = createInitialMetrics("empty");

    // When dashboard data is computed
    const dashboard = computeDashboardData(metrics);

    // Then all metric cards show zero or placeholder values
    expect(dashboard.runningCost.value).toBe("$0.00");
    expect(dashboard.tokenCount.value).toBe("0");
    expect(dashboard.activeAgents.value).toBe("0");
    expect(dashboard.toolCalls.value).toBe("0");
    expect(dashboard.contextWindow.value).toBe("0%");

    // And the dashboard indicates onboarding state
    expect(dashboard.isOnboarding).toBe(true);
  });
});

describe("Hook health card shows amber for newly started session", () => {
  it("zero hook events produce 'No Events' with amber urgency", () => {
    // Given a newly started session with no hook events
    const metrics = createMetricsSnapshot({ hookEventCount: 0 });

    // When dashboard data is computed
    const dashboard = computeDashboardData(metrics);

    // Then hook health shows 'No Events' in amber
    expect(dashboard.hookHealth.value).toBe("No Events");
    expect(dashboard.hookHealth.urgency).toBe("amber");
  });
});

describe("Dashboard title includes session identifier", () => {
  it("sessionLabel contains the session ID for an active session", () => {
    // Given an active session with a known ID
    const metrics = createMetricsSnapshot({ sessionId: "refactor-auth" });

    // When dashboard data is computed
    const dashboard = computeDashboardData(metrics);

    // Then the session label identifies the session
    expect(dashboard.sessionLabel).toBe("refactor-auth");
  });

  it("sessionLabel is empty for the default session", () => {
    // Given metrics from the default session
    const metrics = createMetricsSnapshot({ sessionId: "default" });

    // When dashboard data is computed
    const dashboard = computeDashboardData(metrics);

    // Then no session label is shown
    expect(dashboard.sessionLabel).toBe("");
  });
});

describe("Context window card shows urgency at high utilization", () => {
  it("context at 90% shows red urgency on the context card", () => {
    // Given a session with 90% context utilization
    const metrics = createMetricsSnapshot({ contextWindowPct: 90 });

    // When dashboard data is computed
    const dashboard = computeDashboardData(metrics);

    // Then the context window card shows red urgency
    expect(dashboard.contextWindow.urgency).toBe("red");
  });
});

